(() => {
    if (window.busuanziRequestSent) return; window.busuanziRequestSent = true; const u = new URL('https://cdn.busuanzi.cc/'); fetch(u.protocol + '//' + u.host + '/api.php', { method: 'POST', body: JSON.stringify({ url: location.href, referrer: document.referrer }) }).then(r => r.json()).then(r => {
        for (const k in r) {// 兼容 butterfly 主题：busuanzi_site_uv → busuanzi_value_site_uv
            const domId = k.replace(/^(busuanzi_)(site_|page_|today_)/, '$1value_$2');[domId, k].forEach(id => document.querySelectorAll('#' + id).forEach(e => e.innerText = r[k]))
        }
    }).catch(e => console.error(e))
})()